import{_ as e,o as a,c as i,a as n}from"./app.d3707837.js";var t="/aktivitaeten/BDM-2026-01/00_01-2026.jpg",r="/aktivitaeten/BDM-2026-01/01_01-2026.jpg",s="/aktivitaeten/BDM-2026-01/02_01-2026.jpg",d="/aktivitaeten/BDM-2026-01/03_01-2026.jpg",m="/aktivitaeten/BDM-2026-01/04_01-2026.jpg",l="/aktivitaeten/BDM-2026-01/05_01-2026.jpg",o="/aktivitaeten/BDM-2026-01/06_01-2026.jpg",u="/aktivitaeten/BDM-2026-01/07_01-2026.jpg",h="/aktivitaeten/BDM-2026-01/08_01-2026.jpg",p="/aktivitaeten/BDM-2026-01/09_01-2026.jpg",c="/aktivitaeten/BDM-2026-01/10_01-2026.jpg",g="/aktivitaeten/BDM-2026-01/11_01-2026.jpg",_="/aktivitaeten/BDM-2026-01/12_01-2026.jpg",v="/aktivitaeten/BDM-2026-01/13_01-2026.jpg",k="/aktivitaeten/BDM-2026-01/14_01-2026.jpg",B="/aktivitaeten/BDM-2026-01/15_01-2026.jpg",M="/aktivitaeten/BDM-2026-01/16_01-2026.jpg",D="/aktivitaeten/BDM-2026-01/17_01-2026.jpg",b="/aktivitaeten/BDM-2026-01/18_01-2026.jpg",f="/aktivitaeten/BDM-2026-01/19_01-2026.jpg",w="/aktivitaeten/BDM-2026-01/20_01-2026.jpg",z="/aktivitaeten/BDM-2026-01/21_01-2026.jpg",A="/aktivitaeten/BDM-2026-01/22_01-2026.jpg",S="/aktivitaeten/BDM-2026-01/23_01-2026.jpg",j="/aktivitaeten/BDM-2026-01/24_01-2026.jpg",T="/aktivitaeten/BDM-2026-01/25_01-2026.jpg",W="/aktivitaeten/BDM-2026-01/26_01-2026.jpg",G="/aktivitaeten/BDM-2026-01/27_01-2026.jpg",C="/aktivitaeten/BDM-2026-01/28_01-2026.jpg",E="/aktivitaeten/BDM-2026-01/29_01-2026.jpg",O="/aktivitaeten/BDM-2026-01/30_01-2026.jpg",P="/aktivitaeten/BDM-2026-01/31_01-2026.jpg",F="/aktivitaeten/BDM-2026-01/32_01-2026.jpg",K="/aktivitaeten/BDM-2026-01/33_01-2026.jpg",H="/aktivitaeten/BDM-2026-01/34_01-2026.jpg",R="/aktivitaeten/BDM-2026-01/35_01-2026.jpg",L="/aktivitaeten/BDM-2026-01/36_01-2026.jpg",J="/aktivitaeten/BDM-2026-01/37_01-2026.jpg",N="/aktivitaeten/BDM-2026-01/38_01-2026.jpg",Q="/aktivitaeten/BDM-2026-01/39_01-2026.jpg",V="/aktivitaeten/BDM-2026-01/40_01-2026.jpg";const U={},I=n('<h1 id="bilder-des-monats-januar-2026" tabindex="-1"><a class="header-anchor" href="#bilder-des-monats-januar-2026" aria-hidden="true">#</a> Bilder des Monats Januar 2026</h1><p>Winter POTA</p><p>Bei 2 Grad Eisregen und Winterst\xE4rke 10? Aber es juckt in den POTA Fingern. Nur die harten bekommen auch das begehrte POTA Diplom in der ersten Woche des Jahres.</p><p>Heute mal mit anderer Antenne nachdem uns die Groundplane die Tage immer umgeweht wurde. Die gut 20m mit 1:49 Einspeisung hatte ich schon in der Eifel ausprobiert. Heute aber nicht horizontal gespannt sondern ein Ende am kurzen GFK Spiderbeam in windiger H\xF6he. Gut das ich vier Spanngurte dabei hatte. Das andere Ende an einem Deichzaun befestigt und dann mit Mantelwellensperre in den 705. Der diesmal mal nicht frieren musste, er hat es sich auf der Mittelarmlehne im Auto bequem gemacht.</p><p>Gute Wahl, viele Windb\xF6en haben uns auch da ordentlich durchgesch\xFCttelt. Drau\xDFen die ganze Aktivierung, das w\xE4re wohl zu kalt. Erst war ich an der Reihe. Nach gut 20 Minuten 10 QSO auf 40m - dann hat Christiane \xFCbernommen.</p><p>Bei ihr sofort 2 QSOs auf 15 dann lange nichts. Lass uns mal FT4 probieren. Das lief super, USA, Azoren, Kuweit \u2026.. so macht das Spa\xDF.</p><p>Nach gut 90 Minuten Abbau, erst einmal alles provisorisch in den Kofferraum. Sortieren kann man das ja in Ruhe im warmen.</p><p>Jetzt noch schnell die \u201EBuchf\xFChrung\u201C und schwups nach dem Logbuch Upload ist es schon da.</p><p>Fazit : Hei\xDFer Tee und Betrieb im Auto macht es ertr\xE4glich. GFK Mast hat gehalten. Manchmal sahen wir ihn schon auf unserem Auto\u2026 Und die tolle Aussicht vom Deich. Hammer</p><p>vy 73 Gerd DL2EGS &amp; Christiane DA6CE</p><p><img src="'+t+'" alt="Bilder des Monats"><img src="'+r+'" alt="Bilder des Monats"><img src="'+s+'" alt="Bilder des Monats"><img src="'+d+'" alt="Bilder des Monats"><img src="'+m+'" alt="Bilder des Monats"><img src="'+l+'" alt="Bilder des Monats"><img src="'+o+'" alt="Bilder des Monats"><img src="'+u+'" alt="Bilder des Monats"></p><p>In den letzen Tagen des alten Jahres haben wir DE-1086 Au\xDFenems aktiviert. Da wir nicht ins matschige Watt wollten kam nur eine Stelle an der Seebr\xFCcke Knock in Frage.</p><p>Leider waren da nur Betonplatten ( aber immerhin keine Matsche ). Nur wollte die MC-750 auf ihrem Stativ nicht darauf stehen.</p><p>So haben wir abwechselnd Stativbeschwerer gespielt.</p><p>Kurz dann noch eine EFHW zwischen zwei Masten ausprobiert. Da diese horizontal in gut 1,5m schon recht gut klappte haben wir sie dann im neuen Jahr ausprobiert.</p><p><img src="'+h+'" alt="Bilder des Monats"><img src="'+p+'" alt="Bilder des Monats"><img src="'+c+'" alt="Bilder des Monats"><img src="'+g+'" alt="Bilder des Monats"></p><p>Fotos vom traditionellen &quot;Last SOTA &amp; POTA Point of the Year&quot; von DO1HFS. Jedes Jahr am 31.12. vom H\xF6gl aus QRV. SOTA Referenz: DL/CG-107 und POTA Referenz: DE-1003. Zusammen mit Wasti DL8MEK war das wieder ein spa\xDFiger Vormittag bei -7Grad Celsius und bestem Kaiserwetter \u{1F642} Getestet wurde auch, zum ersten mal, das BaumShack von DL8MEK. Eine Eurobox mit Spanngurt an einem Baumstamm befestigt.</p><p><img src="'+_+'" alt="Bilder des Monats"><img src="'+v+'" alt="Bilder des Monats"><img src="'+k+'" alt="Bilder des Monats"><img src="'+B+'" alt="Bilder des Monats"><img src="'+M+'" alt="Bilder des Monats"><img src="'+D+'" alt="Bilder des Monats"></p><p>Fast jeden Sonntag laufe ich morgens einige km. L\xE4ufst du auch bei Minusgraden? Na klar. Warum denn nicht!</p><p>Gut in Funktionskleidung \u201Everpackt\u201C ging es bei -8 Grad heute mit Laufrucksack zum Tetraeder. ( POTA Referenz DE-0327 Halde Beckstrasse )</p><p>Wir hatten Gl\xFCck, und konnten bei bestem Winter Sonnenwetter bis nach oben auf die Plattform.</p><p>Gemeinsam mit DO1TRE habe ich in gut 14 Minuten mehr als 20 Direkt QSO auf 2m / 70cm und 23cm in Ham2K PoLo loggen k\xF6nnen, DL2EGS.</p><p><img src="'+b+'" alt="Bilder des Monats"><img src="'+f+'" alt="Bilder des Monats"><img src="'+w+'" alt="Bilder des Monats"><img src="'+z+'" alt="Bilder des Monats"></p><p>Gr\xFC\xDFe von Phillip, DL9PK aus dem Volkspark Sch\xF6nholzer Heide, auf dem Weg zum Kilo-Award. Bei einer l\xE4ngeren Session deutlich unter dem Gefrierpunkt musste ich immer wieder H\xE4nde und F\xFC\xDFe auftauen, gelohnt hat es sich aber: 60 POTA-QSOs sind auf dem Weg zu den 1000 QSOs aus dem Park dazu gekommen.</p><p><img src="'+A+'" alt="Bilder des Monats"><img src="'+S+'" alt="Bilder des Monats"></p><p>Heute hatte ich als W6/DC1TC mal wieder die M\xF6glichkeit einen f\xFCr mich neuen Park zu aktivieren. Bei einem Zwischenstopp beim Santa Cruz County Amateur Radio Club zum Winter Field Day bekam ich die Empfehlung f\xFCr diese Location in US-3574 Sunset State Beach. Dank anf\xE4nglich ung\xFCnstiger Wahl des Antennenorts, einem vorher ungetestetem neuen Mikro am FX-4CR, das offenbar \xFCbersteuerte und allgemeinem Gedr\xE4nge auf dem Band durch Winter Field Day war die Aktivierung eher anstrengend. Als WFD vorbei war, ich die Antenne umgestellt hatte und auf das eingebaute Mikro gewechselt bin kamen dann doch endlich mehr Kontakte zusammen.</p><p><img src="'+j+'" alt="Bilder des Monats"><img src="'+T+'" alt="Bilder des Monats"></p><p>Feierabendaktivierung von US-3482 Natural Bridges SB als W6/DC1TC. Anschlie\xDFend habe ich noch mit einem Kollegen den Sonnenuntergang \xFCber dem Pazifik genossen.</p><p><img src="'+W+'" alt="Bilder des Monats"><img src="'+G+'" alt="Bilder des Monats"><img src="'+C+'" alt="Bilder des Monats"></p><p>Am 18.01. habe ich in Hamburg den Jacobipark, DE-0260, aktiviert und es kamen auf 20m und 40m schnell unz\xE4hlige QSOs zusammen. Nach ca. einer Stunde kam DN9OK dazu und hat das 10m-Band unsicher gemacht. Insgesamt eine sehr entspannte Aktivierung.</p><p>Harm, DK4HAA</p><p><img src="'+E+'" alt="Bilder des Monats"><img src="'+O+'" alt="Bilder des Monats"></p><p>Am letzten vollen Tag dieses Trips habe ich mich noch einmal etwas fr\xFCher aus dem B\xFCro geschlichen, um noch eine POTA-Aktivierung als W6/DC1TC zu machen. In US-7375 Cowell Ranch State Beach habe ich eine Bank mit Tisch sowie super Ausblick auf den Pazifik gefunden auf der ich auf 20m gem\xFCtlich erst ein bisschen SSB und dann noch CW-Betrieb gemacht habe. So habe ich 17 US-Bundesstaaten inklusive Alaska und Hawaii sowie Kanada erreichen k\xF6nnen und hatte einen sehr sch\xF6nen Sonnenuntergang.\u{1F305}</p><p><img src="'+P+'" alt="Bilder des Monats"><img src="'+F+'" alt="Bilder des Monats"><img src="'+K+'" alt="Bilder des Monats"><img src="'+H+'" alt="Bilder des Monats"><img src="'+R+'" alt="Bilder des Monats"></p><p>OE3OGC und ich, OE3JLY, haben einen spontanen Ausflug nach Rom unternommen und dabei zwei Parks aktiviert. IT-0719 umfasst ein gro\xDFes Gebiet entlang der Via Appia Antica. Folgt man dieser Stra\xDFe, gelangt man zur Villa der Quintilier, wo man die antiken \xDCberreste der Anlage, erbaut um 150 n. Chr., erkunden kann. Die Villa war seinerzeit derma\xDFen luxuri\xF6s, dass Kaiser Commodus die Besitzer unter einem Vorwand hinrichten lie\xDF, um sie anschlie\xDFend als seine Residenz zu nutzen. Mit diesem Wissen ausgestattet nutzten auch wir diese Residenz als eindrucksvolle Kulisse f\xFCr unsere Aktivierung.</p><p>Da Metall-Erdspie\xDFe im Handgep\xE4ck bei Fluglinien eher ungern gesehen sind, mussten wir improvisieren und waren diesmal mit einem Kamerastativ sowie einem \xBC-Zoll auf M10 Gewindeadapter unterwegs. Nach einer erfolgreichen Aktivierung mit 28 QSOs machten uns auf den R\xFCckweg.</p><p>Am n\xE4chsten Tag stand IT-0256 auf dem Plan, ein Park mit zwei getrennten Teilgebieten. Unsere Wahl fiel auf die Anlagen der Villa Doria Pamphili, da es uns die dort zahlreich vorhandenen italienischen Steinkiefern angetan hatten. Die Bedingungen waren gut, lediglich der Wind war f\xFCr unser provisorisches Setup nicht optimal.</p><p>Insbesondere die Villa der Quintilier ist ein absoluter Geheimtipp f\xFCr POTA, sollte es jemanden einmal nach Rom verschlagen.</p><p><img src="'+L+'" alt="Bilder des Monats"><img src="'+J+'" alt="Bilder des Monats"><img src="'+N+'" alt="Bilder des Monats"><img src="'+Q+'" alt="Bilder des Monats"></p><p>Auf dem Weg zum Flughafen habe ich als W6/DC1TC doch noch eine Aktivierung in US-7493 Candlestick Point State Recreation Area rein gequetscht. Ganz offensichtlich bin ich nicht so gut rausgekommen und es hat deutlich l\xE4nger gedauert als erhofft. Ich habe es gerade noch so rechtzeitig zum Flughafen zur Gep\xE4ckabgabe geschafft, aber daf\xFCr noch einen zus\xE4tzlichen Park in der SF Bay Area aktiviert. \u{1F605}</p><p><img src="'+V+'" alt="Bilder des Monats"></p>',41),x=[I];function y(q,Z){return a(),i("div",null,x)}var X=e(U,[["render",y],["__file","2026-01-30-Bilder-Des-Monats-Januar.html.vue"]]);export{X as default};
